{
  "title": "Mastering Burmese Curries: An Intermediate Cooking Course",
  "description": "This course is designed for intermediate cooks who want to deepen their understanding and skills in preparing authentic Burmese curries. Through a combination of theory and hands-on practice, learners will explore the unique flavors and techniques that define Burmese cuisine.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Burmese Cuisine",
      "description": "Explore the history, ingredients, and key characteristics of Burmese cuisine, with a focus on the role of curries in traditional meals."
    },
    {
      "id": "module2",
      "title": "Essential Ingredients and Tools for Burmese Curries",
      "description": "Learn about the essential spices, herbs, and tools needed to create authentic Burmese curries, including how to source and prepare them."
    },
    {
      "id": "module3",
      "title": "Techniques for Perfecting Curry Bases",
      "description": "Master the techniques for creating rich and flavorful curry bases, including the use of pastes, broths, and balancing flavors."
    },
    {
      "id": "module4",
      "title": "Cooking and Pairing Burmese Curries",
      "description": "Hands-on cooking sessions where learners will prepare a variety of Burmese curries, along with suggestions for side dishes and accompaniments."
    }
  ]
}
